module RefModule(a, b, result);input [7:0] a;
    input [7:0] b;
    output reg [15:0] result;
    integer obf_i; // Declare obf_i as an integer

    always @ (a, b)
    begin
        result = 0;
        for (obf_i = 0; obf_i < 8; obf_i = obf_i + 1)
        begin
            if (b[obf_i] == 1)
            begin
                result = result + (a << obf_i);
            end
        end
    end
endmodule
